%[text] # Design Cooling System 
%[text] 
%[text] 
%[text] ![](text:image:4663)
%[text] ### Requirements for X-Ray Tube Cooling
%[text] 1. Remove a maximum of 2 kW
%[text] 2. Allowed coolant temperature rise 5°C
%[text] 3. Temperature set point: 25°C
%[text] 4. Device temperature should not exceed 50°C
%[text] 5. Working fluid: Water
%[text] 6. Working fluid pressurized at 2 bar
%[text] 7. Temperature stability +/- n°C
%[text] 8. Operating conditions: Inside at room temperature at 20°C  \
%%
%[text] #### Sizing and testing the cooling loop components 
%[text] The steps to parameterize and build the components in Simscape are organized into specific scripts:
%[text] 1. [Cold Plate](file:.\ColdPlate.m)
%[text] 2. [Pump](file:.\Pump.m)
%[text] 3. [Radiator](file:.\Radiator.m) \
%%
%[text] #### Assembling and testing the cooling loop components - Open loop
%[text] We start the assembly of the overall system, by connecting them in an open loop fashion. For better reuse of the individual components have been put into Subsystem References:
open_system("ColdPlateSubsystem")
open_system("RadiatorSubsystem")
open_system("PipingSubsystem")
open_system("PumpSubsystem")
%[text] Note that the pump model has configured the pump rotational velocity as an input, so it can in a next step be connected to a test input and further to the output of the control. Also, the pump inertia's *Rotational velocity* initial value is set to a *Priority* of *None,* since this will directly be connected to a velocity input. Similarly, the heat input to the device mass and cold plate is configured to receive an external input from a Simulink signal, so we can later define different operating scenarios. 
%[text] All Subsystem References are connected into one model thet test input into the pump is a step functions which steps up to the pumps reference speed to create the desired flow for a maximum heat load. The system is intialized at a pressurized at 2 bar, and at the desired coolant inlet temperature of 25°C. The .mat file that is loaded contains all necessary parameters that were also created in the scripts parameterizing the cold plate, pump and radiator.  
load(projRoot+"\Data\coolingSystemParams.mat")
open_system("example_System_Assembly")   
%[text] ![](text:image:2aaa)
%%
simInp = Simulink.SimulationInput("example_System_Assembly");
simInp = simInp.setModelParameter("StopTime","150");

simOut = sim(simInp);

% Extract results
% Pump
VDotSim             = simOut.simlog.Pump.Centrifugal_Pump_TL.q_A.series.values("lpm");
% Devide
TDeviceSim          = simOut.simlog.ColdPlate.Device.M.T.series.values("degC");
% Cold plate
TCPInletSim         = simOut.simlog.ColdPlate.Parallel_Channels.A.T.series.values("degC");
TCPOutletSim        = simOut.simlog.ColdPlate.Parallel_Channels.B.T.series.values("degC");
pCPInletSim         = simOut.simlog.ColdPlate.Parallel_Channels.A.p.series.values("bar");
pCPOutletSim        = simOut.simlog.ColdPlate.Parallel_Channels.B.p.series.values("bar");
% Radiator
TRadiatorInletSim   = simOut.simlog.Radiator.Heat_Exchanger_TL_MA.A1.T.series.values("degC");
TRadiatorOutletSim  = simOut.simlog.Radiator.Heat_Exchanger_TL_MA.B1.T.series.values("degC");
pRadiatorInletSim   = simOut.simlog.Radiator.Heat_Exchanger_TL_MA.A1.p.series.values("bar");
pRadiatorOutletSim  = simOut.simlog.Radiator.Heat_Exchanger_TL_MA.B1.p.series.values("bar");
% Piping
pPipingInletSim     = simOut.simlog.Piping.Pipe_TL.A.p.series.values("bar");
pPipingOutletSim    = simOut.simlog.Piping.Pipe_TL.B.p.series.values("bar");


figure %[output:34ab4432]
plot(simOut.tout,[TDeviceSim,TCPInletSim,TCPOutletSim,TRadiatorInletSim,TRadiatorOutletSim]) %[output:34ab4432]
xlabel("Time [s]") %[output:34ab4432]
ylabel("T [°C]") %[output:34ab4432]
legend("T_{Device}","T_{Cold plate,In}","T_{Cold plate,Out}","T_{Radiator,In}","T_{Radiator, Out}") %[output:34ab4432]

figure %[output:3141252f]
plot(simOut.tout,[pCPInletSim,pCPOutletSim,pRadiatorInletSim,pPipingOutletSim]) %[output:3141252f]
xlabel("Time [s]") %[output:3141252f]
ylabel("p [bar]") %[output:3141252f]
legend("p_{Cold plate,In}","p_{Cold plate,Out}","p_{Radiator,In}","p_{Piping, Out}") %[output:3141252f]



% Assemble table to display
Measurement         = ["VDot [lpm]";"T_Device [degC]";"T_cp,in [degC]";"T_cp,out [degC]";"T_rad,in [degC]";"T_rad,out [degC]";...
            "p_cp,in [bar]";"p_cp,out [bar]";"p_rad,in [bar]";"p_rad,out [bar]";"p_piping,in [bar]";"p_piping,out [bar]"];

MeasurementValues   = [VDotSim(end);TDeviceSim(end);TCPInletSim(end);TCPOutletSim(end);TRadiatorInletSim(end);TRadiatorOutletSim(end);...
    pCPInletSim(end);pCPOutletSim(end);pRadiatorInletSim(end);pRadiatorOutletSim(end);pPipingInletSim(end);pPipingOutletSim(end)];

outputTable = table(Measurement, MeasurementValues);
disp(outputTable) %[output:694596b0]
%[text] The table shows the temperatures and pressures staying well within the expected values. 
%%
%[text] #### Assembling and testing the cooling loop components - Closed loop
%[text] Next, we can close the fluid loop and remove the constant boundary condition (the reservoirs)
open_system("example_System_Assembly_ClosedLoop")   
%[text] Notice that in this version, the piping subsystem is replaced by a subsystem which additionally contains a [Gas-Charged Accumulator (TL)](https://www.mathworks.com/help/releases/R2025a/hydro/ref/gaschargedaccumulatortl.html) block. In a closed loop Thermal Liquid network, as fluid temperature changes the density will increase or decrease, an accumulator or tank can provide additional liquid or absorb excess liquid.   
open_system("example_System_Assembly_ClosedLoop/PipingAccumulator")   
%[text] ![](text:image:7366)

simInp = Simulink.SimulationInput("example_System_Assembly_ClosedLoop");
simInp = simInp.setModelParameter("StopTime","200");

simOut = sim(simInp);

% Extract results
% Pump
VDotSim             = simOut.simlog.Pump.Centrifugal_Pump_TL.q_A.series.values("lpm");
% Devide
TDeviceSim          = simOut.simlog.ColdPlate.Device.M.T.series.values("degC");
% Cold plate
TCPInletSim         = simOut.simlog.ColdPlate.Parallel_Channels.A.T.series.values("degC");
TCPOutletSim        = simOut.simlog.ColdPlate.Parallel_Channels.B.T.series.values("degC");
pCPInletSim         = simOut.simlog.ColdPlate.Parallel_Channels.A.p.series.values("bar");
pCPOutletSim        = simOut.simlog.ColdPlate.Parallel_Channels.B.p.series.values("bar");
% Radiator
TRadiatorInletSim   = simOut.simlog.Radiator.Heat_Exchanger_TL_MA.A1.T.series.values("degC");
TRadiatorOutletSim  = simOut.simlog.Radiator.Heat_Exchanger_TL_MA.B1.T.series.values("degC");
pRadiatorInletSim   = simOut.simlog.Radiator.Heat_Exchanger_TL_MA.A1.p.series.values("bar");
pRadiatorOutletSim  = simOut.simlog.Radiator.Heat_Exchanger_TL_MA.B1.p.series.values("bar");
% Piping
pPipingInletSim     = simOut.simlog.PipingAccumulator.Pipe_TL.A.p.series.values("bar");
pPipingOutletSim    = simOut.simlog.PipingAccumulator.Pipe_TL.B.p.series.values("bar");


figure %[output:25c16640]
plot(simOut.tout,[TDeviceSim,TCPInletSim,TCPOutletSim,TRadiatorInletSim,TRadiatorOutletSim]) %[output:25c16640]
xlabel("Time [s]") %[output:25c16640]
ylabel("T [°C]") %[output:25c16640]
legend("T_{Device}","T_{Cold plate,In}","T_{Cold plate,Out}","T_{Radiator,In}","T_{Radiator, Out}") %[output:25c16640]

figure %[output:21bb8c85]
plot(simOut.tout,[pCPInletSim,pCPOutletSim,pRadiatorInletSim,pPipingOutletSim]) %[output:21bb8c85]
xlabel("Time [s]") %[output:21bb8c85]
ylabel("p [bar]") %[output:21bb8c85]
legend("p_{Cold plate,In}","p_{Cold plate,Out}","p_{Radiator,In}","p_{Piping, Out}") %[output:21bb8c85]



% Assemble table to display
Measurement         = ["VDot [lpm]";"T_Device [degC]";"T_cp,in [degC]";"T_cp,out [degC]";"T_rad,in [degC]";"T_rad,out [degC]";...
            "p_cp,in [bar]";"p_cp,out [bar]";"p_rad,in [bar]";"p_rad,out [bar]";"p_piping,in [bar]";"p_piping,out [bar]"];

MeasurementValues   = [VDotSim(end);TDeviceSim(end);TCPInletSim(end);TCPOutletSim(end);TRadiatorInletSim(end);TRadiatorOutletSim(end);...
    pCPInletSim(end);pCPOutletSim(end);pRadiatorInletSim(end);pRadiatorOutletSim(end);pPipingInletSim(end);pPipingOutletSim(end)];

outputTable = table(Measurement, MeasurementValues);
disp(outputTable) %[output:1ba678f2]
%%
%[text] #### Assembling and testing the cooling loop components - Closed loop
%[text] The pump will be controlled to ensure the coldplate outlet temperature stays below the maximum allowed value of 30°C. 
open_system("example_System_Assembly_ClosedLoop_Logic")   
%[text] ![](text:image:170a)
%[text] The actual outlet temperature is measured after the cold plate subsystem, the system has a simple logic which turns on the pump at 30°C and runs at 25% reference speed once the temperature hits 25°C. 
%[text] 
